import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const Login = () => {
  const [formData, setFormData] = useState({
    LoginName: '',
    Password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthLogin', formData);
      
      if (!response.data) {
        throw new Error('No response data received from server');
      }

      // Store the JWT token and user info
      const token = response.data.token;
      const clientCode = response.data.ClientCode || response.data.clientCode; // Try both cases
      
      if (!token) {
        throw new Error('No token received from server');
      }

      const userInfo = {
        Username: formData.LoginName,
        ClientCode: clientCode
      };

      if (!userInfo.ClientCode) {
        console.warn('Client code not found in response:', response.data);
        // Try to extract from token if available
        try {
          const tokenData = JSON.parse(atob(token.split('.')[1]));
          if (tokenData.ClientCode) {
            userInfo.ClientCode = tokenData.ClientCode;
          }
        } catch (e) {
          console.error('Failed to extract client code from token:', e);
        }
      }

      if (!userInfo.ClientCode) {
        throw new Error('Client code not received from server');
      }
      
      localStorage.setItem('token', token);
      localStorage.setItem('userInfo', JSON.stringify(userInfo));
      
      // Show success message
      toast.success(`Welcome ${userInfo.Username}! Client Code: ${userInfo.ClientCode}`, {
        position: "top-right",
        autoClose: 3000,
        hideProgressBar: false,
        closeOnClick: true,
        pauseOnHover: true,
        draggable: true,
      });

      // Redirect to dashboard after a short delay
      setTimeout(() => {
        navigate('/dashboard');
      }, 2000);

    } catch (err) {
      console.error('Login error:', err);
      const errorMessage = err.response?.data?.Message || err.message || 'Login failed. Please try again.';
      setError(errorMessage);
      toast.error(errorMessage, {
        position: "top-right",
        autoClose: 3000,
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container mt-5">
      <ToastContainer />
      <div className="row justify-content-center">
        <div className="col-md-6">
          <div className="card" style={{ 
            background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
            boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
          }}>
            <div className="card-body">
              <div className="text-center mb-4">
                <i className="fas fa-rfid fa-3x text-primary mb-3"></i>
                <h2 className="card-title">RFID API Login</h2>
                <p className="text-muted">Enter your credentials to access the RFID API Dashboard</p>
              </div>
              {error && (
                <div className="alert alert-danger">
                  <i className="fas fa-exclamation-circle me-2"></i>
                  {error}
                </div>
              )}
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="LoginName" className="form-label">
                    <i className="fas fa-user me-2"></i>
                    Login Name
                  </label>
                  <input
                    type="text"
                    className="form-control"
                    id="LoginName"
                    name="LoginName"
                    value={formData.LoginName}
                    onChange={handleChange}
                    required
                    placeholder="Enter your login name"
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="Password" className="form-label">
                    <i className="fas fa-lock me-2"></i>
                    Password
                  </label>
                  <input
                    type="password"
                    className="form-control"
                    id="Password"
                    name="Password"
                    value={formData.Password}
                    onChange={handleChange}
                    required
                    placeholder="Enter your password"
                  />
                </div>
                <button
                  type="submit"
                  className="btn btn-primary w-100"
                  disabled={loading}
                >
                  {loading ? (
                    <>
                      <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                      Logging in...
                    </>
                  ) : (
                    <>
                      <i className="fas fa-sign-in-alt me-2"></i>
                      Login
                    </>
                  )}
                </button>
              </form>
              <div className="text-center mt-3">
                <p>
                  Don't have an account?{' '}
                  <a href="/register" className="text-primary">
                    <i className="fas fa-user-plus me-1"></i>
                    Register
                  </a>
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
